import{_ as d,o as t,c as o,a3 as c}from"./chunks/framework.BveOjhN0.js";const b=JSON.parse('{"title":"代码生成","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/code-generation.md","filePath":"cosmos/basic-app/code-generation.md","lastUpdated":1783300196000}'),a={name:"cosmos/basic-app/code-generation.md"};function r(n,e,s,l,i,p){return t(),o("div",null,[...e[0]||(e[0]=[c(`<h1 id="代码生成" tabindex="-1">代码生成 <a class="header-anchor" href="#代码生成" aria-label="Permalink to &quot;代码生成&quot;">​</a></h1><p><code>XiHan.BasicApp.CodeGeneration</code> 是一等独立模块，做<strong>数据库优先（DbFirst）的全栈代码生成</strong>：扫描一张已有数据库表的结构 → 落成可编辑的表/列配置 → 用 Scriban 模板渲染出<strong>后端实体到前端页面</strong>的整套 CRUD 代码 → 预览、打 Zip 下载或受控落盘。目标是把&quot;加一张表就要抄一遍八个后端文件 + 三个前端文件&quot;的重复劳动一键铺开。</p><h2 id="模块全景" tabindex="-1">模块全景 <a class="header-anchor" href="#模块全景" aria-label="Permalink to &quot;模块全景&quot;">​</a></h2><p>生成链路由几个协作角色组成，职责单一、可替换：</p><table tabindex="0"><thead><tr><th>角色</th><th>类型</th><th>职责</th></tr></thead><tbody><tr><td>编排应用服务</td><td><code>CodeGenerationAppService</code></td><td>对外入口：权限、事务、DTO 转换、历史留痕；导入 → 预览 → 生成 → 下载</td></tr><tr><td>结构导入器</td><td><code>IDatabaseSchemaImporter</code> / <code>DatabaseSchemaImporter</code></td><td>DbFirst 扫描库表元信息（列名/类型/可空/主键）</td></tr><tr><td>类型映射器</td><td><code>ITypeMappingProvider</code> / <code>DefaultTypeMappingProvider</code></td><td>DB 列类型 → C# 类型 / TS 类型 + 默认表单控件 / 查询方式</td></tr><tr><td>生成引擎</td><td><code>ICodeGenerationEngine</code> / <code>CodeGenerationEngine</code></td><td>管线编排：建模 → 选模板 → 渲染 → 产出</td></tr><tr><td>模板渲染器</td><td><code>ITemplateRenderer</code> / <code>ScribanTemplateRenderer</code></td><td>用<strong>原生 Scriban</strong> 渲染模板（见下文约定）</td></tr><tr><td>渲染器解析器</td><td><code>ITemplateRendererResolver</code></td><td>按 <code>TemplateEngine</code> 选渲染器；当前仅 Scriban</td></tr><tr><td>打包器</td><td><code>IGeneratedArtifactPackager</code> / <code>ZipArtifactPackager</code></td><td>产物清单 → Zip 字节流</td></tr><tr><td>落盘写入器</td><td><code>IGeneratedArtifactWriter</code> / <code>FileSystemArtifactWriter</code></td><td>受控落盘（默认禁用 + 白名单 + 路径穿越拒绝）</td></tr></tbody></table><p>四张配置实体（均 <code>BasicAppFullAuditedEntity</code>，软删、多租户、审计俱全）：</p><table tabindex="0"><thead><tr><th>实体</th><th>表</th><th>作用</th></tr></thead><tbody><tr><td><code>SysCodeGenDataSource</code></td><td><code>Sys_CodeGen_DataSource</code></td><td>外部数据库连接（多库逆向工程），<code>SourceName</code> 全局唯一</td></tr><tr><td><code>SysCodeGenTable</code></td><td><code>Sys_CodeGen_Table</code></td><td>一张目标表的生成主配置，<code>TableName</code> 全局唯一</td></tr><tr><td><code>SysCodeGenTableColumn</code></td><td><code>Sys_CodeGen_TableColumn</code></td><td>列级配置（类型映射、表单控件、查询方式、字典三分）</td></tr><tr><td><code>SysCodeGenTemplate</code></td><td><code>Sys_CodeGen_Template</code></td><td>模板（Scriban 正文 + 文件名/路径表达式），<code>TemplateCode</code> 全局唯一</td></tr></tbody></table><p>生成历史另存 <code>SysCodeGenHistory</code>：每次执行生成——无论成败——都写一条留痕（批次号、耗时、文件数、总字节、操作人、失败原因）。</p><h2 id="三种生成模式" tabindex="-1">三种生成模式 <a class="header-anchor" href="#三种生成模式" aria-label="Permalink to &quot;三种生成模式&quot;">​</a></h2><p>由 <code>SysCodeGenTable.TemplateType</code>（枚举 <code>TemplateType</code>）决定，也是模板筛选的分组维度：</p><table tabindex="0"><thead><tr><th>模式</th><th>枚举</th><th>适用场景</th><th>关键配置字段</th></tr></thead><tbody><tr><td>单表</td><td><code>Single</code></td><td>扁平 CRUD（如岗位、字典项、普通业务表）</td><td>主键列</td></tr><tr><td>树形</td><td><code>Tree</code></td><td>自引用层级（如菜单、部门、地区）</td><td><code>TreeParentColumn</code>（父级字段）、<code>TreeNameColumn</code>（名称字段）</td></tr><tr><td>主从</td><td><code>MasterDetail</code></td><td>一主多从（如订单 + 订单明细）</td><td><code>MasterTableId</code>（主表配置）、<code>MasterForeignKey</code>（子表外键列）</td></tr></tbody></table><p>无显式指定模板编码时，引擎按表的 <code>TemplateType</code> 取该类型下的启用模板集（<code>GetEnabledByTypeAsync</code>）。模板<strong>不按业务模块过滤</strong>——CRUD 模板对所有模块通用，只按模板类型分组。</p><blockquote><p>树形/主从的结构字段（父级列、名称列、主表、外键）通过 <code>CodeGenerationContext.Options</code> 透出给模板（键为 <code>TreeParentColumn</code> / <code>MasterForeignKey</code> 等），模板按 <code>TemplateType</code> 消费。当前内置模板套件以单表为主，树/主从的上下文已就绪，模板可自行扩展。</p></blockquote><h2 id="全栈生成-从实体到前端页面" tabindex="-1">全栈生成：从实体到前端页面 <a class="header-anchor" href="#全栈生成-从实体到前端页面" aria-label="Permalink to &quot;全栈生成：从实体到前端页面&quot;">​</a></h2><p>一次生成铺开<strong>后端 8 件 + 前端 3 件</strong>的整套 CRUD，均为内置模板（<code>IsBuiltIn=true</code>，分组 <code>backend-crud</code> / <code>frontend-crud</code>）：</p><table tabindex="0"><thead><tr><th>模板编码</th><th>产物</th><th>文件名表达式</th></tr></thead><tbody><tr><td><code>backend.entity</code></td><td>实体</td><td><code>{{ ClassName }}.cs</code></td></tr><tr><td><code>backend.dtos</code></td><td>DTO 集</td><td><code>{{ ClassName }}Dtos.cs</code></td></tr><tr><td><code>backend.irepository</code></td><td>仓储接口</td><td><code>I{{ ClassName }}Repository.cs</code></td></tr><tr><td><code>backend.repository</code></td><td>仓储实现</td><td><code>{{ ClassName }}Repository.cs</code></td></tr><tr><td><code>backend.contracts</code></td><td>应用契约</td><td><code>I{{ ClassName }}Contracts.cs</code></td></tr><tr><td><code>backend.mapper</code></td><td>对象映射</td><td><code>{{ ClassName }}ApplicationMapper.cs</code></td></tr><tr><td><code>backend.appservice</code></td><td>应用服务</td><td><code>{{ ClassName }}AppService.cs</code></td></tr><tr><td><code>backend.queryservice</code></td><td>查询服务</td><td><code>{{ ClassName }}QueryService.cs</code></td></tr><tr><td><code>frontend.types</code></td><td>TS 类型</td><td><code>{{ ClassNameKebab }}.types.ts</code></td></tr><tr><td><code>frontend.api</code></td><td>接口请求</td><td><code>{{ ClassNameKebab }}.ts</code></td></tr><tr><td><code>frontend.page</code></td><td>列表页</td><td><code>index.vue</code></td></tr></tbody></table><p>前端产物落到 <code>src/api/modules/&lt;module&gt;/</code> 与 <code>src/views/&lt;module&gt;/&lt;class-kebab&gt;/</code>（路径表达式里 <code>ModuleName</code> 会 <code>string.downcase</code>）。生成的前端页直接用项目的 <code>SchemaPage</code> 组件驱动列表 + 表单弹窗，与手写页面同构。</p><p>除模板产物外，引擎每次还追加<strong>二阶产物</strong>（目录 <code>_GeneratedMenuPermission/</code>）：</p><ul><li><code>{{ClassName}}PermissionCodes.cs</code>——权限码常量类（资源段取表名，<code>{资源}:{操作}</code> 两段式）。</li><li><code>README.md</code>——落地说明：权限码表、按钮→权限码映射、<code>SysMenu</code> 菜单规格、以及&quot;并入源码 → 重建库经 Seeder 生效&quot;的步骤清单。</li></ul><blockquote><p>二阶产物是<strong>待并入源码的代码片段，不是运行时写库</strong>。这符合 BasicApp 的单一事实源 + 菜单即绑约定：把片段并入源码、重建数据库，菜单与权限经既有 Seeder 链生效，避免与&quot;部署重建库&quot;冲突。</p></blockquote><h2 id="数据源与表结构" tabindex="-1">数据源与表结构 <a class="header-anchor" href="#数据源与表结构" aria-label="Permalink to &quot;数据源与表结构&quot;">​</a></h2><h3 id="数据源" tabindex="-1">数据源 <a class="header-anchor" href="#数据源" aria-label="Permalink to &quot;数据源&quot;">​</a></h3><p><code>SysCodeGenDataSource</code> 描述一个外部数据库连接（主机/端口/库名/账号/加密密码或连接串），供跨库逆向工程。要点：</p><ul><li><code>DatabaseType</code> 决定元信息扫描的 SQL 方言，支持 <code>MySql</code> / <code>SqlServer</code> / <code>PostgreSql</code> / <code>Oracle</code> / <code>Sqlite</code>。</li><li>密码/连接串<strong>加密存储</strong>；保存前<strong>测试连接</strong>必须通过（留痕 <code>LastTestTime</code> / <code>LastTestResult</code>）。</li><li>删除前校验无 <code>SysCodeGenTable</code> 引用。</li><li><code>ConnectionConfigId</code> 为空时使用<strong>主库</strong>元数据（生成器自身所在库）。</li></ul><h3 id="表结构导入" tabindex="-1">表结构导入 <a class="header-anchor" href="#表结构导入" aria-label="Permalink to &quot;表结构导入&quot;">​</a></h3><p>导入是&quot;逆向工程&quot;的入口，由 <code>CodeGenerationAppService.ImportTableAsync</code> 闭环完成：</p><ol><li><strong>去重</strong>——同一目标表禁止重复配置（<code>TableName</code> 全局唯一）。</li><li><strong>扫描结构</strong>——<code>DatabaseSchemaImporter</code> 接通框架 <code>IDatabaseMetadataProvider</code>，只产出数据库层结构（列名/类型/可空/主键/自增/长度/小数位）。</li><li><strong>建表配置</strong>——类名默认由表名 <code>Pascalize</code>（<code>sys_user</code> → <code>SysUser</code>），可覆盖命名空间/模块/业务名/作者。</li><li><strong>建列配置</strong>——每列经 <code>ITypeMappingProvider.Map</code> 预填 C#/TS 类型、默认表单控件（<code>HtmlType</code>）与查询方式（<code>QueryType</code>），并写默认开关（<code>IsList=true</code> / <code>IsInsert=true</code> / <code>IsEdit=true</code> / <code>IsQuery=false</code>）。</li></ol><p>导入器有两处贴合本仓约定的健壮处理：</p><ul><li><strong>大小写还原</strong>：部分库（如 MySQL <code>lower_case_table_names=1</code>）返回全小写名，丢失驼峰。导入器反射已注册的 <code>[SugarTable]</code> 实体建名称目录，把 <code>syscodegendatasource</code> 还原为 <code>SysCodeGenDataSource</code>；未注册的外部表保持原样。</li><li><strong>分表折叠</strong>：带 <code>[SplitTable]</code> 的日志类实体物理表按时间分片（如 <code>sysdifflog_20260601</code>）。列表时把同实体的所有分片折叠为基础逻辑名（<code>SysDiffLog</code>）去重；导入基础名时自动扫最近一个分片取列结构。</li></ul><h3 id="字段配置" tabindex="-1">字段配置 <a class="header-anchor" href="#字段配置" aria-label="Permalink to &quot;字段配置&quot;">​</a></h3><p><code>SysCodeGenTableColumn</code> 是列级精细控制面，模板据此渲染。常用字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>CSharpType</code> / <code>CSharpProperty</code> / <code>TsType</code></td><td>类型与属性名映射（导入预填、可手改）</td></tr><tr><td><code>HtmlType</code></td><td>表单控件：<code>Input</code> / <code>Textarea</code> / <code>Select</code> / <code>Switch</code> / <code>DatePicker</code> / <code>InputNumber</code> / <code>TreeSelect</code> …</td></tr><tr><td><code>QueryType</code></td><td>查询方式：<code>Equal</code> / <code>Like</code> / <code>Between</code> / <code>In</code> …</td></tr><tr><td><code>IsList</code> / <code>IsInsert</code> / <code>IsEdit</code> / <code>IsQuery</code></td><td>列表显示 / 新增 / 编辑 / 查询开关</td></tr><tr><td><code>IsRequired</code> / <code>ColumnLength</code> / <code>MinValue</code> / <code>MaxValue</code> / <code>RegexPattern</code></td><td>表单校验约束</td></tr></tbody></table><p><strong>字典三分</strong>（选项列的可选项来源，由 <code>DictSelectorType</code> 决定生效字段）：</p><table tabindex="0"><thead><tr><th><code>DictSelectorType</code></th><th>生效字段</th><th>含义</th></tr></thead><tbody><tr><td><code>DictSelector</code></td><td><code>DictCode</code></td><td>关联系统字典类型编码</td></tr><tr><td><code>EnumSelector</code></td><td><code>EnumTypeName</code></td><td>关联枚举全名</td></tr><tr><td><code>ConstSelector</code></td><td><code>ConstValues</code></td><td>内联常量项 JSON</td></tr></tbody></table><blockquote><p><strong>字典三分是纯表单渲染信息，不入生成的领域代码</strong>——它只让前端页把某列渲染成对应下拉/选项，不产生任何跨表关联或外键。</p></blockquote><h2 id="模板-基于-scriban-可自定义" tabindex="-1">模板：基于 Scriban，可自定义 <a class="header-anchor" href="#模板-基于-scriban-可自定义" aria-label="Permalink to &quot;模板：基于 Scriban，可自定义&quot;">​</a></h2><p>模板存在 <code>SysCodeGenTemplate.TemplateContent</code>（BigString）。内置模板由 <code>SysCodeGenTemplateSeeder</code> 把 <code>Templates/Backend/*.sbn</code>、<code>Templates/Frontend/*.sbn</code>（编译为嵌入资源）种入库、标 <code>IsBuiltIn=true</code>；用户可新增自定义模板或改动非内置模板。</p><h3 id="模板变量" tabindex="-1">模板变量 <a class="header-anchor" href="#模板变量" aria-label="Permalink to &quot;模板变量&quot;">​</a></h3><p>引擎把 <code>CodeGenerationContext</code> 投影成 PascalCase 键的 Scriban 变量。顶层常用：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ClassName          实体类名（如 SysProduct）</span></span>
<span class="line"><span>ClassNameCamel     camelCase（sysProduct）— 前端标识/API 对象名</span></span>
<span class="line"><span>ClassNameKebab     kebab-case（sys-product）— 前端文件名/路由</span></span>
<span class="line"><span>TableName          数据库表名</span></span>
<span class="line"><span>TableComment       表注释</span></span>
<span class="line"><span>Namespace / ModuleName / BusinessName / FunctionName / Author</span></span>
<span class="line"><span>TemplateType       枚举以名称字符串透出（&quot;Single&quot;/&quot;Tree&quot;/&quot;MasterDetail&quot;）</span></span>
<span class="line"><span>PrimaryKey         主键列（字典）</span></span>
<span class="line"><span>Columns            列集合（字典列表）</span></span>
<span class="line"><span>Options            扩展键（树/主从结构字段、ParentMenuId 等）</span></span></code></pre></div><p>每个 <code>Columns</code> 项（字典）常用键：<code>ColumnName</code> / <code>ColumnComment</code> / <code>CSharpType</code> / <code>CSharpProperty</code> / <code>TsProperty</code>（camelCase，对应后端 camelCase JSON）/ <code>TsType</code> / <code>IsPrimaryKey</code> / <code>IsNullable</code> / <code>IsRequired</code> / <code>HtmlType</code> / <code>QueryType</code> / <code>DictSelectorType</code> / <code>DictCode</code>，以及关键的 <strong><code>IsBaseColumn</code></strong>。</p><blockquote><p><code>IsBaseColumn</code> 标记基类 <code>BasicAppFullAuditedEntity</code> 托管的列（<code>BasicId</code> / <code>TenantId</code> / <code>IsDeleted</code> / 审计四段 / 软删三段）。模板据它跳过这些列，只生成业务属性——否则会重复声明基类已有成员。内置 <code>Entity.sbn</code> 里可见 <code>{{~ if !col.IsBaseColumn ~}}</code> 的用法。</p></blockquote><h3 id="文件名-路径表达式" tabindex="-1">文件名 / 路径表达式 <a class="header-anchor" href="#文件名-路径表达式" aria-label="Permalink to &quot;文件名 / 路径表达式&quot;">​</a></h3><p>模板另有两个表达式字段（本身也走 Scriban 渲染）：</p><ul><li><code>FileNameExpression</code>——输出文件名，如 <code>{{ ClassName }}Dtos.cs</code>；渲染失败或为空时回退 <code>ClassName</code> + <code>FileExtension</code>。</li><li><code>FilePathExpression</code>——输出目录（相对路径），拼在文件名前；渲染失败回退无目录输出。</li></ul><h3 id="约定-1-生成代码不焊外键关联" tabindex="-1">约定 ①：生成代码不焊外键关联 <a class="header-anchor" href="#约定-1-生成代码不焊外键关联" aria-label="Permalink to &quot;约定 ①：生成代码不焊外键关联&quot;">​</a></h3><p><strong>生成的代码不建立任何物理/对象层外键关联</strong>——没有 SqlSugar <code>Navigate</code> 导航属性、没有 LEFT JOIN、没有物理外键、没有跨表&quot;显示属性&quot;。跨表关联一律由业务层手写。上文的字典三分（<code>DictSelector</code> / <code>EnumSelector</code> / <code>ConstSelector</code>）保留，但它只是<strong>表单选项来源</strong>，同样不入生成代码。这与代码生成器的既定方向一致：生成物保持自包含、无隐式耦合，关联关系交给人显式表达。</p><h3 id="约定-2-用原生-scriban-而非框架-itemplateservice" tabindex="-1">约定 ②：用原生 Scriban，而非框架 <code>ITemplateService</code> <a class="header-anchor" href="#约定-2-用原生-scriban-而非框架-itemplateservice" aria-label="Permalink to &quot;约定 ②：用原生 Scriban，而非框架 \`ITemplateService\`&quot;">​</a></h3><p>渲染由 <code>ScribanTemplateRenderer</code> 直接用<strong>原生 Scriban</strong> 完成：<code>Template.Parse(...)</code> 解析、<code>ScriptObject</code> 注入变量、<code>TemplateContext</code> 渲染，并关闭成员重命名（<code>MemberRenamer = member =&gt; member.Name</code>），使模板以确定的 PascalCase 访问变量。</p><p>它<strong>刻意不走</strong>框架的 <code>ITemplateService</code>——后者对 <code>string</code> 的默认引擎是<strong>简单替换引擎，不解析 Scriban 语法</strong>（<code>{{ }}</code>、<code>for</code>、<code>if</code>），会把模板原样输出。要真正跑 Scriban 语法就必须绕开它、用原生 Scriban。这一点在 <code>ScribanTemplateRenderer</code> 的注释里有明确说明。渲染前可用 <code>Validate</code> 做语法校验（<code>Template.Parse</code> 报错即返回 <code>TemplateRenderValidation.Invalid</code>）。</p><blockquote><p>枚举移除了 Razor（需运行时编译、框架不支持，避免&quot;选了报错&quot;的伪能力）；<code>T4</code> 在枚举中保留占位，但解析器目前只注册了 Scriban，选其它引擎会抛 <code>NotSupportedException</code>。</p></blockquote><h2 id="生成流程" tabindex="-1">生成流程 <a class="header-anchor" href="#生成流程" aria-label="Permalink to &quot;生成流程&quot;">​</a></h2><p>对外方法（<code>CodeGenerationAppService</code>，经 <code>[DynamicApi]</code> 暴露，分组 <code>BasicApp.CodeGen</code>）与权限：</p><table tabindex="0"><thead><tr><th>步骤</th><th>方法</th><th>权限码</th></tr></thead><tbody><tr><td>列库表</td><td><code>ListDatabaseTablesAsync</code></td><td><code>code_gen:read</code></td></tr><tr><td>导入表结构</td><td><code>ImportTableAsync</code></td><td><code>code_gen:import</code></td></tr><tr><td>预览</td><td><code>PreviewAsync</code></td><td><code>code_gen:read</code></td></tr><tr><td>执行生成</td><td><code>GenerateAsync</code></td><td><code>code_gen:execute</code></td></tr></tbody></table><p>端到端流程：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>选数据源（或主库）</span></span>
<span class="line"><span>  → 列出库表、导入目标表         [ImportTableAsync]</span></span>
<span class="line"><span>      · 扫结构 + 类型映射 → 落表/列配置</span></span>
<span class="line"><span>  → 调整表配置（模板类型/命名空间/模块）与列配置（控件/查询/字典三分）</span></span>
<span class="line"><span>  → 预览                          [PreviewAsync → GenType.Preview]</span></span>
<span class="line"><span>      · 建 CodeGenerationContext → 逐模板渲染 → 返回产物清单（含内容）</span></span>
<span class="line"><span>  → 执行生成                      [GenerateAsync]</span></span>
<span class="line"><span>      · 同渲染核心，再按 GenType 分流产出</span></span>
<span class="line"><span>      · 无论成败写一条 SysCodeGenHistory 留痕</span></span></code></pre></div><p>生成方式由 <code>GenType</code> 决定：</p><table tabindex="0"><thead><tr><th><code>GenType</code></th><th>行为</th></tr></thead><tbody><tr><td><code>Preview</code></td><td>只返回产物清单（含文件内容），不打包不落盘</td></tr><tr><td><code>Zip</code></td><td>打成 Zip，包体以 <strong>Base64</strong> 随 <code>CodeGenResultDto.PackageBase64</code> 返回，前端触发下载</td></tr><tr><td><code>CustomPath</code></td><td><strong>受控落盘</strong>到 <code>SysCodeGenTable.GenPath</code></td></tr></tbody></table><h3 id="落盘的安全策略-fail-closed" tabindex="-1">落盘的安全策略（fail-closed） <a class="header-anchor" href="#落盘的安全策略-fail-closed" aria-label="Permalink to &quot;落盘的安全策略（fail-closed）&quot;">​</a></h3><p><code>CustomPath</code> 落盘由 <code>FileSystemArtifactWriter</code> 把关，绑定配置节 <code>CodeGeneration</code>（<code>CodeGenerationOptions</code>），<strong>默认禁用</strong>，任一条件不满足即拒绝：</p><ul><li><code>EnableCustomPathDisk=false</code>（默认）→ 拒绝。</li><li><code>AllowedRootPaths</code> 为空 → 拒绝。</li><li>目标路径不在白名单根目录内 → 拒绝。</li><li>产物相对路径是绝对路径 / 带盘符 / 拼接后越界（<code>..</code> 逃逸）→ 拒绝。</li></ul><p>即&quot;默认禁用 + 白名单根目录 + 路径穿越二次校验&quot;，符合本仓 fail-closed 约定。生产要落盘须显式开启并配置白名单。</p><h2 id="扩展与二次开发" tabindex="-1">扩展与二次开发 <a class="header-anchor" href="#扩展与二次开发" aria-label="Permalink to &quot;扩展与二次开发&quot;">​</a></h2><ul><li><strong>加一种数据库方言</strong>：扩展 <code>ITypeMappingProvider</code> 的映射；扫描能力依赖框架 <code>IDatabaseMetadataProvider</code>。</li><li><strong>加/改模板</strong>：新增 <code>SysCodeGenTemplate</code>（自定义编码、Scriban 正文、文件名/路径表达式），或改动非内置模板；用模板变量表与 <code>IsBaseColumn</code> 约定编写。</li><li><strong>换渲染引擎</strong>：实现 <code>ITemplateRenderer</code>（<code>Engine</code> 返回对应 <code>TemplateEngine</code>）并注册，<code>TemplateRendererResolver</code> 后注册覆盖先注册。</li><li><strong>生成后并入源码</strong>：按 <code>_GeneratedMenuPermission/README.md</code> 的步骤把权限码常量、种子（资源→权限→菜单→授权，Order 用 200+ 段）并入模块，<strong>重建数据库</strong>使菜单与权限到位。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./../framework/packages/templating">框架 · 模板模块</a>：框架 <code>ITemplateService</code> 的定位与简单替换引擎（为何代码生成绕开它用原生 Scriban）。</li><li><a href="./../framework/concepts/dynamic-api">框架 · 动态 API</a>：<code>[DynamicApi]</code> 如何把 <code>CodeGenerationAppService</code> 暴露为 REST。</li><li><a href="./permissions">权限模型</a>：<code>code_gen:*</code> 权限码、菜单即绑与二阶产物落地的背景。</li><li><a href="./architecture">系统架构</a>：模块在启动聚合中的装配位置。</li></ul>`,66)])])}const u=d(a,[["render",r]]);export{b as __pageData,u as default};
